/**
 * onResponse.ts
 * 
 * Response Generated Hook Implementation
 * 
 * This hook is triggered when a response is generated by the LLM.
 * It allows plugins to process, modify, or analyze responses before
 * they are displayed to the user.
 * 
 * @module HookImplementations
 * @author Claude Code Clone
 * @version 1.0.0
 */

import { HookDefinition, HookCategory, HookExecutionOrder, OnResponseData, HookContext } from '../types';

/**
 * onResponse hook definition
 */
export const onResponseDefinition: HookDefinition<OnResponseData> = {
  name: 'onResponse',
  description: 'Called when a response is generated by the LLM. Plugins can process, modify, or analyze responses.',
  category: HookCategory.MESSAGE,
  executionOrder: HookExecutionOrder.SEQUENTIAL,
  cancellable: false,
  defaultTimeout: 5000,
  allowModification: true,
  stopOnError: false,
  stopOnSuccess: false,
  examples: [
    `// Log responses
plugin.registerHook('onResponse', async (context) => {
  const { responseId, content, model, tokenUsage } = context.data;
  console.log(\`[\${model}] Tokens: \${tokenUsage.total}\`);
});`,
    `// Add signature to responses
plugin.registerHook('onResponse', async (context) => {
  const signature = '\\n\\n---\\nGenerated by Claude Code';
  context.appendContent(signature);
});`,
    `// Filter sensitive information
plugin.registerHook('onResponse', async (context) => {
  const { content } = context.data;
  const filtered = content.replace(/\\b\\d{4}[\\s-]?\\d{4}[\\s-]?\\d{4}[\\s-]?\\d{4}\\b/g, '[CARD NUMBER REMOVED]');
  context.set('content', filtered);
});`
  ],
  relatedHooks: ['onMessage', 'onStreamToken'],
  schema: {
    input: {
      type: 'object',
      properties: {
        responseId: { type: 'string', description: 'Unique response ID' },
        content: { type: 'string', description: 'Response content' },
        model: { type: 'string', description: 'Model name' },
        tokenUsage: {
          type: 'object',
          properties: {
            prompt: { type: 'number' },
            completion: { type: 'number' },
            total: { type: 'number' }
          }
        },
        duration: { type: 'number', description: 'Generation duration in ms' },
        timestamp: { type: 'string', format: 'date-time' }
      },
      required: ['responseId', 'content', 'model', 'tokenUsage', 'duration', 'timestamp']
    }
  }
};

/**
 * onResponse hook context
 */
export interface OnResponseContext extends HookContext<OnResponseData> {
  /** Append content to the response */
  appendContent(text: string): void;
  /** Prepend content to the response */
  prependContent(text: string): void;
  /** Replace content in the response */
  replaceContent(search: string | RegExp, replacement: string): void;
  /** Truncate response if too long */
  truncate(maxLength: number, suffix?: string): void;
  /** Format the response (e.g., markdown formatting) */
  format(formatter: (content: string) => string): void;
  /** Add metadata to the response */
  addMetadata(key: string, value: any): void;
  /** Get token usage statistics */
  getTokenStats(): { prompt: number; completion: number; total: number; cost?: number };
  /** Check if response contains code blocks */
  hasCodeBlocks(): boolean;
  /** Extract code blocks from response */
  extractCodeBlocks(): Array<{ language?: string; code: string }>;
  /** Log the response */
  log(level: 'debug' | 'info' | 'warn' | 'error', message: string): void;
}

/**
 * Creates an onResponse hook context
 */
export function createOnResponseContext(
  data: OnResponseData,
  executionId: string
): OnResponseContext {
  return {
    hookName: 'onResponse',
    data,
    executionId,
    timestamp: new Date(),
    cancelled: false,
    metadata: {},

    get<K extends keyof OnResponseData>(key: K): OnResponseData[K] {
      return data[key];
    },

    set<K extends keyof OnResponseData>(key: K, value: OnResponseData[K]): void {
      (data as any)[key] = value;
    },

    cancel(reason?: string): void {
      this.cancelled = true;
      this.cancellationReason = reason;
    },

    addMeta(key: string, value: any): void {
      this.metadata[key] = value;
    },

    appendContent(text: string): void {
      data.content += text;
      data.modified = true;
      if (!data.originalContent) {
        data.originalContent = data.content.slice(0, -text.length);
      }
    },

    prependContent(text: string): void {
      data.content = text + data.content;
      data.modified = true;
      if (!data.originalContent) {
        data.originalContent = data.content.slice(text.length);
      }
    },

    replaceContent(search: string | RegExp, replacement: string): void {
      const original = data.content;
      data.content = data.content.replace(search, replacement);
      if (data.content !== original) {
        data.modified = true;
        if (!data.originalContent) {
          data.originalContent = original;
        }
      }
    },

    truncate(maxLength: number, suffix: string = '...'): void {
      if (data.content.length > maxLength) {
        if (!data.originalContent) {
          data.originalContent = data.content;
        }
        data.content = data.content.substring(0, maxLength - suffix.length) + suffix;
        data.modified = true;
      }
    },

    format(formatter: (content: string) => string): void {
      if (!data.originalContent) {
        data.originalContent = data.content;
      }
      data.content = formatter(data.content);
      data.modified = true;
    },

    addMetadata(key: string, value: any): void {
      if (!data.metadata) {
        data.metadata = {};
      }
      data.metadata[key] = value;
    },

    getTokenStats(): { prompt: number; completion: number; total: number; cost?: number } {
      const { prompt, completion, total } = data.tokenUsage;
      
      // Estimate cost (would use actual pricing in production)
      const costPer1K = {
        prompt: 0.003,
        completion: 0.015
      };
      
      const cost = (prompt / 1000 * costPer1K.prompt) + 
                   (completion / 1000 * costPer1K.completion);
      
      return { prompt, completion, total, cost };
    },

    hasCodeBlocks(): boolean {
      return /```[\s\S]*?```/.test(data.content);
    },

    extractCodeBlocks(): Array<{ language?: string; code: string }> {
      const blocks: Array<{ language?: string; code: string }> = [];
      const regex = /```(\w+)?\n([\s\S]*?)```/g;
      let match;
      
      while ((match = regex.exec(data.content)) !== null) {
        blocks.push({
          language: match[1],
          code: match[2].trim()
        });
      }
      
      return blocks;
    },

    log(level: 'debug' | 'info' | 'warn' | 'error', message: string): void {
      console[level](`[onResponse] ${message}`);
    }
  };
}

/**
 * Default onResponse handler
 */
export async function defaultOnResponseHandler(context: OnResponseContext): Promise<void> {
  const { responseId, content, model, tokenUsage, duration } = context.data;
  const stats = context.getTokenStats();
  
  console.log(`[onResponse] ${model} generated response (${tokenUsage.total} tokens) in ${duration}ms`);
  
  if (stats.cost) {
    console.log(`Estimated cost: $${stats.cost.toFixed(4)}`);
  }
  
  // Extract and log code blocks
  const codeBlocks = context.extractCodeBlocks();
  if (codeBlocks.length > 0) {
    console.log(`Response contains ${codeBlocks.length} code block(s)`);
  }
  
  // Add metadata
  context.addMetadata({
    processedAt: new Date().toISOString(),
    codeBlocks: codeBlocks.length,
    contentLength: content.length,
    estimatedCost: stats.cost
  });
}

export default onResponseDefinition;
